import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useUserProfile } from '../contexts/UserProfileContext';
import { transformToFinancialProduct, getRecommendations } from '../utils/finance';
import './UserProfile.css';

const FORM_OPTIONS = {
  riskTolerance:       ['conservative', 'moderate', 'aggressive'],
  investmentHorizon:   ['short', 'medium', 'long'],
  liquidityPreference: ['easy', 'moderate', 'locked'],
  investmentGoal:      ['wealth building', 'retirement', 'emergency fund', 'specific purchase'],
};

const LABELS = {
  riskTolerance:       { conservative: '🛡️ Conservative', moderate: '⚖️ Moderate', aggressive: '🚀 Aggressive' },
  investmentHorizon:   { short: '⚡ Short (1–2 yrs)', medium: '📅 Medium (3–5 yrs)', long: '🌱 Long (5+ yrs)' },
  liquidityPreference: { easy: '💧 Need Quick Access', moderate: '〜 Some Flexibility', locked: '🔒 Can Lock Funds' },
  investmentGoal:      {
    'wealth building': '📈 Wealth Building',
    'retirement': '🏖️ Retirement',
    'emergency fund': '🆘 Emergency Fund',
    'specific purchase': '🎯 Specific Purchase',
  },
};

const DESCRIPTIONS = {
  riskTolerance: {
    conservative: 'I prefer safety over returns. Capital preservation is my priority.',
    moderate: 'I can tolerate some risk for better returns over time.',
    aggressive: 'I am comfortable with volatility for potentially high returns.',
  },
  investmentHorizon: {
    short: 'I need funds within 1–2 years.',
    medium: 'I plan to invest for 3–5 years.',
    long: 'I am investing for 5+ years.',
  },
};

export default function UserProfile() {
  const { profile, updateProfile, clearProfile, INITIAL_PROFILE } = useUserProfile();
  const navigate = useNavigate();
  const [form, setForm]     = useState(profile || { ...INITIAL_PROFILE });
  const [errors, setErrors] = useState({});
  const [saved, setSaved]   = useState(false);
  const [matchCount, setMatchCount] = useState(null);
  const [allProducts, setAllProducts] = useState([]);

  useEffect(() => {
    fetch('https://fakestoreapi.com/products')
      .then(r => r.json())
      .then(data => setAllProducts(data.map(transformToFinancialProduct)))
      .catch(() => {});
  }, []);

  // Live recommendation preview
  useEffect(() => {
    if (!form.riskTolerance || !form.investmentHorizon || !form.monthlyCapacity || !form.liquidityPreference) {
      setMatchCount(null); return;
    }
    const recs = getRecommendations(allProducts, form);
    setMatchCount(recs.length);
  }, [form, allProducts]);

  function handleChange(key, value) {
    setForm(prev => ({ ...prev, [key]: value }));
    setErrors(prev => ({ ...prev, [key]: '' }));
  }

  function validate() {
    const e = {};
    if (!form.riskTolerance)       e.riskTolerance       = 'Select your risk tolerance';
    if (!form.investmentHorizon)   e.investmentHorizon   = 'Select investment horizon';
    if (!form.monthlyCapacity || Number(form.monthlyCapacity) < 1000)
                                   e.monthlyCapacity     = 'Minimum investment capacity is PKR 1,000';
    if (!form.liquidityPreference) e.liquidityPreference = 'Select liquidity preference';
    if (!form.investmentGoal)      e.investmentGoal      = 'Select your investment goal';
    return e;
  }

  function handleSubmit() {
    const e = validate();
    if (Object.keys(e).length > 0) { setErrors(e); return; }
    updateProfile({ ...form, monthlyCapacity: Number(form.monthlyCapacity) });
    setSaved(true);
    setTimeout(() => { setSaved(false); navigate('/recommendations'); }, 1200);
  }

  function handleClear() {
    clearProfile();
    setForm({ ...INITIAL_PROFILE });
    setMatchCount(null);
  }

  return (
    <div className="page page-enter">
      <div className="container">
        <div className="up-header">
          <div>
            <h1 className="section-title">Your <span>Financial Profile</span></h1>
            <p className="section-subtitle">This profile powers your personalized recommendations</p>
          </div>
          {profile && (
            <button className="btn btn-danger btn-sm" onClick={handleClear}>Clear Profile</button>
          )}
        </div>

        <div className="up-layout">
          <div className="up-form">

            {/* Risk Tolerance */}
            <FormSection title="Risk Tolerance" error={errors.riskTolerance}>
              <div className="up-options">
                {FORM_OPTIONS.riskTolerance.map(opt => (
                  <label key={opt} className={`up-option ${form.riskTolerance === opt ? 'selected' : ''}`}>
                    <input type="radio" name="risk" value={opt} checked={form.riskTolerance === opt}
                      onChange={() => handleChange('riskTolerance', opt)} />
                    <div className="up-option-content">
                      <span className="up-option-label">{LABELS.riskTolerance[opt]}</span>
                      <span className="up-option-desc">{DESCRIPTIONS.riskTolerance[opt]}</span>
                    </div>
                  </label>
                ))}
              </div>
            </FormSection>

            {/* Investment Horizon */}
            <FormSection title="Investment Horizon" error={errors.investmentHorizon}>
              <div className="up-options">
                {FORM_OPTIONS.investmentHorizon.map(opt => (
                  <label key={opt} className={`up-option ${form.investmentHorizon === opt ? 'selected' : ''}`}>
                    <input type="radio" name="horizon" value={opt} checked={form.investmentHorizon === opt}
                      onChange={() => handleChange('investmentHorizon', opt)} />
                    <div className="up-option-content">
                      <span className="up-option-label">{LABELS.investmentHorizon[opt]}</span>
                      <span className="up-option-desc">{DESCRIPTIONS.investmentHorizon[opt]}</span>
                    </div>
                  </label>
                ))}
              </div>
            </FormSection>

            {/* Monthly Capacity */}
            <FormSection title="Monthly Investment Capacity (PKR)" error={errors.monthlyCapacity}>
              <input
                type="number"
                className="form-input"
                value={form.monthlyCapacity}
                onChange={e => handleChange('monthlyCapacity', e.target.value)}
                placeholder="e.g. 50000"
                min={1000}
              />
              <p className="up-helper">Minimum: PKR 1,000</p>
            </FormSection>

            {/* Liquidity Preference */}
            <FormSection title="Liquidity Preference" error={errors.liquidityPreference}>
              <div className="up-options">
                {FORM_OPTIONS.liquidityPreference.map(opt => (
                  <label key={opt} className={`up-option ${form.liquidityPreference === opt ? 'selected' : ''}`}>
                    <input type="radio" name="liquidity" value={opt} checked={form.liquidityPreference === opt}
                      onChange={() => handleChange('liquidityPreference', opt)} />
                    <span className="up-option-label">{LABELS.liquidityPreference[opt]}</span>
                  </label>
                ))}
              </div>
            </FormSection>

            {/* Investment Goal */}
            <FormSection title="Primary Investment Goal" error={errors.investmentGoal}>
              <div className="up-goal-grid">
                {FORM_OPTIONS.investmentGoal.map(opt => (
                  <label key={opt} className={`up-goal-btn ${form.investmentGoal === opt ? 'selected' : ''}`}>
                    <input type="radio" name="goal" value={opt} checked={form.investmentGoal === opt}
                      onChange={() => handleChange('investmentGoal', opt)} />
                    {LABELS.investmentGoal[opt]}
                  </label>
                ))}
              </div>
            </FormSection>

            <button
              className={`btn ${saved ? 'btn-primary' : 'btn-primary'} up-submit`}
              onClick={handleSubmit}
            >
              {saved ? '✓ Profile Saved! Redirecting…' : 'Save Profile & Get Recommendations →'}
            </button>
          </div>

          {/* Sidebar: Live preview */}
          <div className="up-sidebar">
            <div className="up-preview card">
              <h3 className="up-preview-title">Profile Preview</h3>
              {[
                { label: 'Risk', val: form.riskTolerance },
                { label: 'Horizon', val: form.investmentHorizon },
                { label: 'Capacity', val: form.monthlyCapacity ? `PKR ${Number(form.monthlyCapacity).toLocaleString()}` : null },
                { label: 'Liquidity', val: form.liquidityPreference },
                { label: 'Goal', val: form.investmentGoal },
              ].map(row => (
                <div key={row.label} className="up-preview-row">
                  <span className="up-preview-label">{row.label}</span>
                  <span className={`up-preview-val ${row.val ? '' : 'empty'}`}>
                    {row.val || '—'}
                  </span>
                </div>
              ))}

              {matchCount !== null && (
                <div className="up-match-count">
                  <span className="up-match-num">{matchCount}</span>
                  <span className="up-match-label">products match your current profile</span>
                </div>
              )}
            </div>

            <div className="up-tip card">
              <p className="up-tip-title">💡 How It Works</p>
              <p className="up-tip-text">
                Your profile is used to filter and rank financial products. 
                Conservative users only see low-risk products. Aggressive users 
                see all risk levels, sorted by highest return first.
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

function FormSection({ title, error, children }) {
  return (
    <div className="up-section">
      <h3 className="up-section-title">{title}</h3>
      {children}
      {error && <p className="form-error">{error}</p>}
    </div>
  );
}
